#include <stdio.h>
#include <stdlib.h>
typedef struct { long long c; long long f; } Pair;
int cmp(const void *a, const void *b) {
    long long ca = ((Pair*)a)->c;
    long long cb = ((Pair*)b)->c;
    return (ca > cb) - (ca < cb);
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *f = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &f[i]);
        Pair *arr = (Pair*)malloc(N*sizeof(Pair));
        for(int i=0;i<N;i++){
            long long c; scanf("%lld", &c);
            arr[i].c = c; arr[i].f = f[i];
        }
        free(f);
        qsort(arr, N, sizeof(Pair), cmp);
        long long need = N;
        long long ans = 0;
        for(int i=0;i<N && need>0;i++){
            long long take = arr[i].f < need ? arr[i].f : need;
            ans += take * arr[i].c;
            need -= take;
        }
        printf("%lld\n", ans);
        free(arr);
    }
    return 0;
}

