#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<long long> f(N);
        for(int i=0;i<N;i++) cin>>f[i];
        vector<pair<long long,long long>> v(N); // {cost, capacity}
        for(int i=0;i<N;i++){
            long long c; cin>>c;
            v[i] = {c, f[i]};
        }
        sort(v.begin(), v.end(), [](auto &a, auto &b){return a.first < b.first;});
        long long need = N;
        long long ans = 0;
        for(auto &p: v){
            if(need==0) break;
            long long take = min(p.second, need);
            ans += take * p.first;
            need -= take;
        }
        cout<<ans<<"\n";
    }
    return 0;
}

