const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let output = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const f = new Array(N);
  for (let i = 0; i < N; i++) f[i] = data[idx++];
  const cars = [];
  for (let i = 0; i < N; i++) {
    const c = data[idx++];
    cars.push({c: c, f: f[i]});
  }
  cars.sort((a, b) => a.c - b.c);
  let need = N;
  let ans = 0;
  for (const car of cars) {
    if (need === 0) break;
    const take = car.f < need ? car.f : need;
    ans += take * car.c;
    need -= take;
  }
  output.push(String(ans));
}
console.log(output.join('\n'));
